        { id: 'TAVERN', label: 'Tavern', icon: Beer },
        { id: 'DUNGEON', label: 'Dungeon', icon: Map },
        { id: 'INVENTORY', label: 'Storage', icon: Package },
        { id: 'SIMULATION', label: 'Sim', icon: Activity },
    ];

    const unlockedTabs = tabs.filter(t => state.unlockedTabs.includes(t.id));

    const renderTab = () => {
        switch (activeTab) {
            case 'FORGE': return <ForgeTab />;
            case 'MARKET': return <MarketTab onNavigate={setActiveTab} />;
            case 'SHOP': return <ShopTab onNavigate={setActiveTab} />;
            case 'TAVERN': return <TavernTab activeTab={activeTab} />;
            case 'DUNGEON': return <DungeonTab />;
            case 'INVENTORY': return <InventoryDisplay />;
            case 'SIMULATION': return <SimulationTab />;
            default: return <ForgeTab />;
        }
    };

    return (
        <div className="flex flex-col h-[100dvh] w-full bg-stone-950 overflow-hidden">
            <Header 
                activeTab={activeTab} 
                onTabChange={setActiveTab} 
                onSettingsClick={() => setShowSettings(true)} 
            />

            <main className="flex-1 relative overflow-hidden">
                {renderTab()}
                {state.activeTutorialScene && <TutorialScene />}
            </main>

            {/* Bottom Navigation */}
            <nav className="flex justify-around items-center bg-stone-900 border-t border-stone-800 p-2 pb-safe shrink-0 z-30">
                {unlockedTabs.map(tab => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`flex flex-col items-center gap-1 transition-all ${activeTab === tab.id ? 'text-amber-500 scale-110' : 'text-stone-500'}`}
                    >
                        <tab.icon className="w-5 h-5" />
                        <span className="text-[8px] md:text-[10px] uppercase font-black tracking-widest">{tab.label}</span>
                    </button>
                ))}
            </nav>

            {/* Global Modals */}
            <EventModal />
            <SleepModal />
            <JournalModal />
            <CraftingResultModal />
            <DungeonResultModal />
            <SettingsModal 
                isOpen={showSettings} 
                onClose={() => setShowSettings(false)} 
                onQuit={onQuit} 
                onLoadRequest={onLoadFromSettings}
            />
            <TutorialCompleteModal />
            <TierUnlockModal />

            {/* Global Toast Notification System */}
            {state.toast?.visible && (
                <div className="fixed bottom-24 left-1/2 -translate-x-1/2 z-[2000] bg-stone-800 text-stone-100 px-6 py-3 rounded-full border border-stone-600 shadow-2xl animate-in slide-in-from-bottom-4 duration-300">
                    <p className="text-xs font-black uppercase tracking-widest">{state.toast.message}</p>
                </div>
            )}
        </div>
    );
};

