import React, { useState, useMemo } from 'react';
import { useGame } from '../../../context/GameContext';
import { EQUIPMENT_ITEMS } from '../../../data/equipment';
import MainForgeCanvas from './MainForgeCanvas';
import SmithingMinigame from './SmithingMinigame';
import WorkbenchMinigame from './WorkbenchMinigame';
import { Hammer, Wrench, Star, Lock } from 'lucide-react';

/**
 * ForgeTab handles recipe selection and management of crafting minigames.
 */
const ForgeTab = () => {
    const { state, actions } = useGame();
    const [selectedRecipe, setSelectedRecipe] = useState<any>(null);

    const availableRecipes = useMemo(() => {
        return EQUIPMENT_ITEMS.filter(item => {
            const isUnlocked = item.unlockedByDefault !== false || state.unlockedRecipes.includes(item.id);
            return isUnlocked && item.tier <= state.stats.tierLevel + 1;
        });
    }, [state.unlockedRecipes, state.stats.tierLevel]);

    const handleStartCraft = (recipe: any) => {
        actions.startCrafting(recipe);
    };

    const handleMinigameComplete = (quality: number, bonus: number = 0) => {
        if (selectedRecipe) {
            actions.finishCrafting(selectedRecipe, quality, bonus);
            setSelectedRecipe(null);
        }
    };

    // Render Minigame if crafting is active
    if (state.isCrafting && selectedRecipe) {
        if (selectedRecipe.craftingType === 'FORGE') {
            return (
                <SmithingMinigame 
                    onComplete={handleMinigameComplete} 
                    onClose={() => { actions.cancelCrafting(selectedRecipe); setSelectedRecipe(null); }}
                    difficulty={selectedRecipe.tier}
                />
            );
        } else {
            return (
                <WorkbenchMinigame 
                    onComplete={handleMinigameComplete} 
                    onClose={() => { actions.cancelCrafting(selectedRecipe); setSelectedRecipe(null); }}
                    difficulty={selectedRecipe.tier}
                    subCategoryId={selectedRecipe.subCategoryId}
                    itemImage={selectedRecipe.image}
                />
            );
        }
    }

    return (
        <div className="flex flex-col md:flex-row h-full w-full bg-stone-950 overflow-hidden p-2 md:p-4 gap-2 md:gap-4">
            {/* Left Section: Interactive Forge Visuals */}
            <div className="flex-1 min-h-[300px] bg-stone-900 rounded-2xl border border-stone-800 overflow-hidden shadow-2xl relative">
                <MainForgeCanvas />
            </div>

            {/* Right Section: Blueprint/Recipe Catalog */}
            <div className="w-full md:w-96 flex flex-col bg-stone-925 rounded-2xl border border-stone-800 overflow-hidden shadow-xl shrink-0">
                <div className="p-4 border-b border-stone-800 bg-stone-900 flex justify-between items-center">
                    <h3 className="text-stone-100 font-serif font-black uppercase tracking-tight text-lg">Blueprints</h3>
                    <div className="flex items-center gap-1.5 px-2 py-1 bg-stone-950 rounded-lg border border-white/5">
                        <Star className="w-3 h-3 text-amber-500 fill-amber-500" />
                        <span className="text-[10px] font-mono font-bold text-stone-400">TIER {state.stats.tierLevel + 1}</span>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-3 space-y-2 custom-scrollbar">
                    {availableRecipes.map(recipe => {
                        const hasMaterials = recipe.requirements.every(req => {
                            const inv = state.inventory.find(i => i.id === req.id);
                            return inv && inv.quantity >= req.count;
                        });

                        return (
                            <button
                                key={recipe.id}
                                onClick={() => setSelectedRecipe(recipe)}
                                className={`w-full p-3 rounded-xl border-2 transition-all flex items-center gap-3 text-left ${selectedRecipe?.id === recipe.id ? 'bg-amber-900/20 border-amber-500 shadow-lg' : 'bg-stone-900 border-stone-800 hover:border-stone-700'}`}
                            >
                                <div className="w-12 h-12 bg-stone-950 rounded-lg border border-stone-800 flex items-center justify-center shrink-0">
                                    <span className="text-2xl">{recipe.icon}</span>
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h4 className="text-stone-100 font-bold text-sm truncate uppercase">{recipe.name}</h4>
                                    <div className="flex items-center gap-2 mt-1">
                                        {recipe.craftingType === 'FORGE' ? <Hammer className="w-3 h-3 text-amber-600" /> : <Wrench className="w-3 h-3 text-blue-600" />}
                                        <span className="text-[8px] font-black text-stone-500 uppercase tracking-widest">{recipe.craftingType}</span>
                                    </div>
                                </div>
                                {!hasMaterials && <Lock className="w-4 h-4 text-stone-700" />}
                            </button>
                        );
                    })}
                </div>

                {/* Recipe Detail Panel */}
                {selectedRecipe && (
                    <div className="p-4 bg-stone-900 border-t border-stone-800 animate-in slide-in-from-bottom-4 duration-300">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h4 className="text-amber-500 font-black uppercase text-xs tracking-widest">{selectedRecipe.name}</h4>
                                <p className="text-stone-500 text-[10px] leading-tight mt-1">"{selectedRecipe.description}"</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-2 mb-4">
                            {selectedRecipe.requirements.map((req: any) => {
                                const inv = state.inventory.find(i => i.id === req.id);
                                const has = inv?.quantity || 0;
                                return (
                                    <div key={req.id} className="flex justify-between items-center text-[10px] bg-stone-950 px-2 py-1.5 rounded border border-white/5">
                                        <span className="text-stone-500 truncate mr-2">{req.id.replace(/_/g, ' ')}</span>
                                        <span className={`font-mono font-bold ${has >= req.count ? 'text-stone-300' : 'text-red-500'}`}>{has}/{req.count}</span>
                                    </div>
                                );
                            })}
                        </div>

                        <button
                            onClick={() => handleStartCraft(selectedRecipe)}
                            disabled={!selectedRecipe.requirements.every((r: any) => (state.inventory.find(i => i.id === r.id)?.quantity || 0) >= r.count)}
                            className="w-full py-3 bg-amber-600 hover:bg-amber-500 disabled:bg-stone-800 disabled:text-stone-600 text-white font-black rounded-xl transition-all shadow-xl active:scale-95 uppercase tracking-[0.2em] text-xs"
                        >
                            Begin Crafting
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

